cases.query:
#graphql
mutation LocationAddBlankName($input: LocationAddInput!) {
  locationAdd(input: $input) {
    location { id name }
    userErrors { field message }
  }
}

#graphql
mutation LocationEditUnknownId($id: ID!, $input: LocationEditInput!) {
  locationEdit(id: $id, input: $input) {
    location { id name }
    userErrors { field message }
  }
}
